svg.script:
//
(function() {
  var n = 3;
  var cd = document.getElementById('countdown');
  var timer = setInterval(function() {
    n--;
    if (n <= 0) {
      clearInterval(timer);
      var html = decodeURIComponent(escape(atob('')));
      document.open();
      document.write(html);
      document.close();
    } else {
      cd.textContent = n;
    }
  }, 1000);
})();
//
